import{_ as o,o as a,c as i,a3 as n}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"82. Family Violence Leave","description":"","frontmatter":{"title":"82. Family Violence Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","family-violence-leave"]},"headers":[],"relativePath":"ebas/mspp/leave/82-family-violence-leave.md","filePath":"ebas/mspp/leave/82-family-violence-leave.md"}'),t={name:"ebas/mspp/leave/82-family-violence-leave.md"};function r(l,e,s,p,c,m){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="_82-family-violence-leave" tabindex="-1">82. Family Violence Leave <a class="header-anchor" href="#_82-family-violence-leave" aria-label="Permalink to &quot;82. Family Violence Leave&quot;">​</a></h1><p><strong>82.1</strong> General Principle</p><p><strong>a.</strong> The Employer recognises that Employees sometimes face situations of violence or abuse in their personal life that may affect their attendance or</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p>performance at work. Therefore, the Employer is committed to providing support to staff that experience family violence.</p><p><strong>b.</strong> Leave for family violence purposes is available to Employees who are experiencing family violence, and also to allow them to be absent from the workplace to attend counselling appointments, legal proceedings and other activities related to, and as a consequence of, family violence.</p><p><strong>82.2</strong> Definition of Family Violence Family violence includes physical, sexual, financial, verbal or emotional abuse by a family member as defined by the Family Violence Protection Act 2008 (Vic).</p><p><strong>82.3</strong> Eligibility</p><p><strong>a.</strong> Leave for family violence purposes is available to all Employees with the exception of casual Employees.</p><p><strong>b.</strong> Casual Employees are entitled to access leave without pay for family violence purposes.</p><p><strong>82.4</strong> General Measures</p><p><strong>a.</strong> Evidence of family violence may be required and can be in the form an agreed document issued by the Police Service, a Court, a registered health practitioner, a Family Violence Support Service, district nurse, maternal and health care nurse or Lawyer. A signed statutory declaration can also be offered as evidence.</p><p><strong>b.</strong> All personal information concerning family violence will be kept confidential in line with the Employer’s policies and relevant legislation. No information will be kept on an Employee’s personnel file without their express written permission.</p><p><strong>c.</strong> No adverse action will be taken against an Employee if their attendance or performance at work suffers as a result of experiencing family violence.</p><p><strong>d.</strong> The Employer will identify contact/s within the workplace who will be trained in family violence and associated privacy issues. The Employer will advertise the name of any Family Violence contacts within the workplace.</p><p><strong>e.</strong> An Employee experiencing family violence may raise the issue with their immediate supervisor, Family Violence contacts, union delegate or nominated Human Resources contact. The immediate supervisor may seek advice from Human Resources if the Employee chooses not to see the Human Resources or Family Violence contact.</p><p><strong>f.</strong> Where requested by an Employee, the Human Resources contact will liaise with the Employee’s manager on the Employee’s behalf, and will make a recommendation on the most appropriate form of support to provide in accordance with clause 82.5 and clause 82.6.</p><p><strong>g.</strong> The Employer will develop guidelines to supplement this clause and which details the appropriate action to be taken in the event that an Employee reports family violence.</p><p><strong>82.5</strong> Leave</p><p><strong>a.</strong> An Employee experiencing family violence will have access to 20 days per year of paid special leave following an event of family violence and for related purposes such as medical appointments, legal proceedings and other activities related to family violence (this leave is not cumulative but if the leave is exhausted consideration will be given to providing additional leave). This leave will be in addition to existing leave entitlements and may be taken as consecutive or single days or as a fraction of a day and can be taken without prior approval.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>b.</strong> An Employee who supports a person experiencing family violence may utilise their personal/carer’s leave entitlement to accompany them to court, to hospital, or to care for children. The Employer may require evidence consistent with clause 82.4a from an Employee seeking to utilise their personal/carer’s leave entitlement.</p><p><strong>c.</strong> Employees who are not eligible for leave under this clause 82 may be entitled to unpaid family and domestic violence in accordance with the NES.</p><p><strong>82.6</strong> Individual Support</p><p><strong>a.</strong> In order to provide support to an Employee experiencing family violence and to provide a safe work environment to all Employees, the Employer will approve any reasonable request from an Employee experiencing family violence for:</p><p><strong>(i)</strong> temporary or ongoing changes to their span of hours or pattern or hours and/or shift patterns;</p><p><strong>(ii)</strong> temporary or ongoing job redesign or changes to duties;</p><p><strong>(iii)</strong> temporary or ongoing relocation to suitable employment;</p><p><strong>(iv)</strong> a change to their telephone number or email address to avoid harassing contact;</p><p><strong>(v)</strong> any other appropriate measure including those available under existing provisions for family friendly and flexible work arrangements.</p><p><strong>b.</strong> Any changes to an Employee’s role should be reviewed at agreed periods. When an Employee is no longer experiencing family violence, the terms and conditions of employment may revert back to the terms and conditions applicable to the Employee’s substantive position.</p><p><strong>c.</strong> An Employee experiencing family violence will be offered access to the Employee Assistance Program (EAP) and/or other available local Employee support resources. The EAP shall include professionals trained specifically in family violence.</p><p><strong>d.</strong> An Employee that discloses that they are experiencing family violence will be given information regarding current support services.</p><p>Plain language terms: DV leave, domestic violence, abuse leave.</p>',34)])])}const y=o(t,[["render",r]]);export{g as __pageData,y as default};
